     263: /// Word-wrap `text` into `#`-prefixed lines, `first_prefix` on the
     264: /// first line and `cont_prefix` on continuations, each kept to
     265: /// `width` columns where possible (a single word longer than
     266: /// `width` still gets its own line, unsplit).
     267: fn wrap_hash_comment(text: &str, first_prefix: &str, cont_prefix: &str, width: usize) -> String {
     268:     let mut lines: Vec<String> = Vec::new();
     269:     let mut current = String::new();
     270:     for word in text.split_whitespace() {
     271:         let prefix_len = if lines.is_empty() {
     272:             first_prefix.len()
     273:         } else {
     274:             cont_prefix.len()
     275:         };
     276:         let sep = usize::from(!current.is_empty());
     277:         let tentative_len = prefix_len + current.len() + sep + word.len();
     278:         if !current.is_empty() && tentative_len > width {
     279:             lines.push(std::mem::take(&mut current));
     280:         }
     281:         if !current.is_empty() {
     282:             current.push(' ');
     283:         }
     284:         current.push_str(word);
     285:     }
     286:     if !current.is_empty() {
     287:         lines.push(current);
     288:     }
     289:     let mut out = String::new();
     290:     for (i, l) in lines.iter().enumerate() {
     291:         let prefix = if i == 0 { first_prefix } else { cont_prefix };
     292:         out.push_str(prefix);
     293:         out.push_str(l);
     294:         out.push('\n');
     295:     }
     296:     out
     297: }
