     299: /// Render one key as a thorough, self-documenting doc-block:
     300: /// - `# <path> — <doc>` (word-wrapped onto `#   ...`
     301: ///   continuations past ~72 cols),
     302: /// - `#   used by: <used_by>`,
     303: /// - `#   default: <rendered default, or a "(none)"/"(required...)"
     304: ///   note>`,
     305: /// - the assignment line itself — uncommented for a `required` key
     306: ///   (init fills in the role-specific value), commented (`# `)
     307: ///   otherwise, with the rendered default or a kind placeholder
     308: ///   (`<str>` etc.) when there is no default,
     309: /// - a trailing blank line, so consecutive blocks read as
     310: ///   paragraph-separated entries.
     311: ///
     312: /// Shared by `crate::config_cmd` (printed schema) and `crate::init`
     313: /// (commented defaults in the generated `.vc-config.toml`) so the
     314: /// two surfaces cannot drift from each other's wording.
     315: pub fn render_key_block(key: &ConfigKey) -> String {
     316:     let mut out = String::new();
     317:     let header_text = format!("{} — {}", key.path, key.doc);
     318:     out.push_str(&wrap_hash_comment(&header_text, "# ", "#   ", 72));
     319:     out.push_str(&format!("#   used by: {}\n", key.used_by));
     320:     out.push_str(&format!("#   default: {}\n", render_default_note(key)));
     321:     let (_section, leaf) = section_and_leaf(key.path);
     322:     let prefix = if key.required { "" } else { "# " };
     323:     let value = render_value(key);
     324:     out.push_str(&format!("{prefix}{leaf} = {value}\n"));
     325:     out.push('\n');
     326:     out
     327: }
